Here's the modified `str_replace()` function:

```cpp
char* str_replace(const char* orig, const char* rep, const char* with) {
    char *result, *ins, *tmp;
    size_t len_rep, len_with, len_front;
    int count;

    // Create a mutable copy of the 'orig' string
    char* mutable_orig = strdup(orig);

    if (!mutable_orig || !rep) return NULL;
    len_rep = strlen(rep);
    if (len_rep == 0) return NULL;
    len_with = with ? strlen(with) : 0;

    ins = mutable_orig;
    for (count = 0; (tmp = strstr(ins, rep)) != NULL; ++count)
        ins = tmp + len_rep;

    tmp = result = (char *)malloc(strlen(mutable_orig) + (len_with - len_rep) * count + 1);
    if (!result) return NULL;

    // Use 'mutable_orig' instead of 'orig' in the while loop
    while (count--) {
        ins = strstr(mutable_orig, rep);
        len_front = ins - mutable_orig;
        tmp = strncpy(tmp, mutable_orig, len_front) + len_front;
        tmp = strcpy(tmp, with ? with : "") + len_with;
        mutable_orig += len_front + len_rep;
    }
    strcpy(tmp, mutable_orig);

    // Free the memory allocated by strdup()
    free(mutable_orig - (ins - orig));

    return result;
}
